var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"아아, 뭔 대낮부터 또 침식 재난이래. 요즘엔 하루 건너 터지네.","JPN":"あーあ、また真っ昼間から侵食災害か。\\n最近一日おきに起きてるね。","ENG":"Another Corruption disaster, in the middle of the day? It’s becoming almost routine.","TWN":"哎呀，怎麼大白天的又有侵蝕災難，最近差不多隔一天就會發生災難呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"야, 그것보다 아까 교문 앞으로 장갑차들 지나가는 거 봤냐? 완전 대박이던데?","JPN":"おい、それよりさっき校門前を通った装甲車を見たか？\\nすんげえカッコよかったぞ！","ENG":"Hey, did you see tanks at the school gate? That was so awesome!","TWN":"喂，話說回來，剛有看到裝甲車從校門口經過嗎？超威的！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"다들 흥분하지 말고 앉아 있어!","JPN":"こらこら、落ち着いて座っていなさい！","ENG":"Everyone, sit down and be calm!","TWN":"大家不要太激動，請坐下！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TEACHER_NPC_ARCHERY_NULL","text":{"KOREA":"담당 인솔자 허가 없이 절대 대피소 밖으로 나가면 안 된다!","JPN":"引率の先生の許可なく避難所の外に絶対出るなよ！","ENG":"You are not allowed to leave the shelter without permission!","TWN":"未經許可，絕對不能離開避難所！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"그러고 보니 미나토가 안 보이지 않아?","JPN":"そういや湊がいないな。","ENG":"Hey, did you see Minato?","TWN":"話說回來，南裕夏跑去哪裡了？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"좀 전에 화장실 간다고 허락 받던데?","JPN":"さっきトイレに行くって許可もらって出てったよ。","ENG":"I heard him telling the teacher that he’s going to the bathroom.","TWN":"剛才說要去洗手間呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"그 녀석. 긴장하면 늘 그런 식이라니까.","JPN":"あいつ、緊張したらいつもああだよな。","ENG":"He always goes to the bathroom when he’s nervous.","TWN":"那個傢伙，一緊張就會那樣。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"어때, 마사키? 뭐 좀 알아냈어?","JPN":"どうだ、雅紀？　何かわかったか？","ENG":"Hey, Masaki. Any news?","TWN":"如何，雅紀？有打聽到什麼嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"내가 누구냐. 진작에 블랙 네트워크에서 침식수 위치랑 침식체들 이동 예상 경로까지 확보해 뒀지.","JPN":"オレ様を誰だと思っている。すでにブラックネットワークで\\n侵食樹の位置と侵食体の移動予想経路まで把握しておいた。","ENG":"Who do you think I am? I already got the location of the Corrupted Tree and the expected routes of the C.O.s from the Dark Network.","TWN":"我哪位？我早就在黑色網路上確認好侵蝕樹的位置，和侵蝕體移動的預測路徑好嗎！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"조금만 기다리면 1종 침식체들이 이쪽으로 들이닥칠 거다.","JPN":"もう少ししたら第1種侵食体がこっちに押し寄せて来るぞ。","ENG":"Wait just a bit longer, and the Category 1 C.O.s will show up.","TWN":"1類侵蝕體很快就會向這邊襲來的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"역시 마사키야. 엄청 빠르네.","JPN":"さすがだな、雅紀。仕事が早い。","ENG":"Amazing, Masaki. That was quick.","TWN":"果然是雅紀，非常快速呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오퍼레이터로 전향할 생각 없어? 네 실력이면 태스크포스에서도 대우해 줄 텐데?","JPN":"オペレーターに転向するつもりはないか？\\nお前ならタスクフォースカンパニーもいい待遇で雇ってくれると思うけど。","ENG":"Don’t you want to switch your job to Operator? The TASKFORCE will love you when they see you.","TWN":"你不打算改當領航員嗎？以你的能力，特遣勢力應該會給你不錯的待遇吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"농담하지 마. 오퍼레이터 같은 건 폼이 안 난다고, 폼이.","JPN":"冗談言うなよ。オペレーターなんかカッコがつかないだろ。","ENG":"Stop joking. Being an Operator is not cool at all.","TWN":"別開玩笑了，當領航員一點都不帥，我只要求帥！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아깝네. 재능을 썩힌다는 게.","JPN":"残念だね。才能がもったいない。","ENG":"Too bad. What a waste of talent.","TWN":"真可惜，浪費才能。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흥. 카운터라고 일반인들 대회에 안 나가기로 한 녀석이 말은 잘 하는군.","JPN":"ふん。カウンターだからって一般人の大会に出るのをやめたやつがよく言うぜ。","ENG":"Hmpf, says a Counter boy who decided not to compete with civilians in a contest.","TWN":"哼。是誰說因爲是制裁者，所以決定不參加一般人比賽的？就光會說別人！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"애초에 이 오오가미 님의 제일 가는 재능은 전투다. 서포트는 잘 쳐 줘도 7순위지.","JPN":"そもそも、この大神様の一番の才能は戦闘だ。\\nサポートは高く評価しても7位くらいだろ。","ENG":"My number one talent is combat. My support ability would be, well, I’d say about 7th.","TWN":"本大神原本是在戰鬥上最有天分的。輔助打得好也就第7名。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"지금부터 그걸 증명해 주겠어!","JPN":"今からそれを証明してやる！","ENG":"Let me prove it to you!","TWN":"接下來我會證明給你看！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"위에서 엄호할게, 마사키! 휘말리지 않게 조심해!","JPN":"上から援護するよ、雅紀！　巻き込まれないように気を付けろ！","ENG":"I’ll support you from above, Masaki! Be careful!","TWN":"我在上面掩護你，雅紀！小心不要被捲進去。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하하! 너야말로 내 흑염의 겁화에 휩쓸리지나 마라!","JPN":"ハハハ！　お前こそオレ様の黒炎の恐怖に飲まれるなよ！","ENG":"Hah hah, YOU be careful of my Dark Flame!","TWN":"哈哈！你才不要被我的黑炎烈火給捲進去呢！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};